const SKIP_DOMAINS = [
  'myshopify.com', 'shopify.com', 'reddit.com', 'youtube.com', 'wikipedia.org',
  'twitter.com', 'facebook.com', 'instagram.com', 'linkedin.com', 'xing.com',
  'google.com', 'amazon.de', 'ebay.de', 'otto.de', 'zalando.de',
  'trustpilot.com', 'yelp.de', 'tripadvisor.de', 'ionos.de', 'wix.com',
  'jimdo.com', 'squarespace.com', 'wordpress.com', 'medium.com'
];

const SKIP_PATHS = [
  '/blog/', '/artikel/', '/news/', '/ratgeber/', '/magazin/',
  '/tutorial/', '/anleitung/', '/hilfe/', '/faq/',
  '/shopify/', '/wordpress/', '/woocommerce/',
  '/entfernen', '/remove', '/deaktivieren'
];

function extractCategory(query) {
  const keywords = [
    'mode', 'fashion', 'beauty', 'kosmetik', 'sport', 'fitness',
    'schmuck', 'accessoires', 'wohnen', 'moebel', 'einrichtung',
    'elektronik', 'technik', 'kueche', 'haushalt', 'gesundheit',
    'wellness', 'baby', 'kinder', 'outdoor', 'camping',
    'haustier', 'tier', 'gaming', 'spiele'
  ];
  const q = query.toLowerCase();
  const found = keywords.find(k => q.includes(k));
  return found ? found.charAt(0).toUpperCase() + found.slice(1) : 'Allgemein';
}

const items = [];
const seen = new Set();

for (const inputItem of $input.all()) {
  const response = inputItem.json;
  if (!response.organic_results) continue;
  const category = extractCategory(response.search_parameters && response.search_parameters.q ? response.search_parameters.q : '');
  for (const result of response.organic_results) {
    if (!result.link) continue;
    try {
      const u = new URL(result.link);
      const domain = u.hostname.replace(/^www\./, '');
      const path = u.pathname.toLowerCase();
      if (!domain.endsWith('.de')) continue;
      if (SKIP_DOMAINS.some(function(s) { return domain.includes(s); })) continue;
      if (SKIP_PATHS.some(function(p) { return path.includes(p); })) continue;
      if (seen.has(domain)) continue;
      seen.add(domain);
      items.push({
        json: {
          brand: result.title || domain,
          domain: domain,
          url: 'https://' + domain,
          category: category,
          description: result.snippet || ''
        }
      });
    } catch (e) {}
  }
}

return items.length ? items : [{ json: { _skip: true } }];

const seen = new Set();
const unique = [];

for (const item of $input.all()) {
  const lead = item.json;
  if (lead._skip || !lead.domain) continue;
  if (seen.has(lead.domain)) continue;
  seen.add(lead.domain);
  unique.push(lead);
}

return unique.map(function(l) { return { json: l }; });
